const express = require('express')
const httpProxy = require("http-proxy");

 const proxyServer = httpProxy.createProxyServer();

 const server = express()
  .use(express.json())
  
 server
  	.all("/proxy/:url", (req, res) => {
      proxyServer.web(req, res, {target:"http://google.com"})
    })

  server.listen(80, ()=>console.log('listening on port 3001'))